def init_db():
    c = sqlite3.connect(DB_PATH)
    c.executescript("""
    CREATE TABLE IF NOT EXISTS history(
        id INTEGER PRIMARY KEY AUTOINCREMENT,
        ts TEXT, category TEXT, ai_name TEXT, prompt TEXT, response TEXT);
    CREATE TABLE IF NOT EXISTS custom_chips(
        id INTEGER PRIMARY KEY AUTOINCREMENT,
        category TEXT, label TEXT, prompt_text TEXT);
    CREATE TABLE IF NOT EXISTS settings(
        key TEXT PRIMARY KEY, value TEXT);
    CREATE TABLE IF NOT EXISTS chains(
        id INTEGER PRIMARY KEY AUTOINCREMENT,
        name TEXT, steps TEXT);
    """)
    c.commit()
    c.close()

def db_get(key, default):
    c = sqlite3.connect(DB_PATH)
    row = c.execute("SELECT value FROM settings WHERE key=?", (key,)).fetchone()
    c.close()
    return row[0] if row else default

def db_set(key, value):
    c = sqlite3.connect(DB_PATH)
    c.execute("INSERT OR REPLACE INTO settings(key,value) VALUES(?,?)", (key, str(value)))
    c.commit()
    c.close()

def db_query(q, params=(), fetch=False):
    c = sqlite3.connect(DB_PATH)
    cur = c.execute(q, params)
    result = cur.fetchall() if fetch else None
    c.commit()
    c.close()
    return result

def get_active_ai():
    return db_get("active_ai", "Claude")

def call_ai(ai_name, category, prompt, rage=False):
    import urllib.request, urllib.error
    key = db_get("key_" + ai_name, "")
    system = GUMNUTS_PREFIX + CATEGORY_SYSTEMS.get(category, CATEGORY_SYSTEMS["others"])
    if rage:
        prompt = prompt + "\n\n" + RAGE_TEXT
    endpoint = AI_DEFS.get(ai_name, {}).get("endpoint", "anthropic")

    if endpoint == "anthropic":
        if not key:
            raise ValueError("No Claude API key set. Go to Settings and add your Anthropic API key.")
        payload = json.dumps({
            "model": db_get("model_Claude", "claude-sonnet-4-6"),
            "max_tokens": 4096,
            "system": system,
            "messages": [{"role": "user", "content": prompt}]
        }).encode()
        req = urllib.request.Request(
            "https://api.anthropic.com/v1/messages", data=payload,
            headers={"x-api-key": key, "anthropic-version": "2023-06-01",
                     "content-type": "application/json"}, method="POST")
        with urllib.request.urlopen(req, timeout=60) as r:
            return json.loads(r.read())["content"][0]["text"]

    elif endpoint in ("openai", "copilot"):
        if not key:
            raise ValueError("No API key set for " + ai_name + ". Go to Settings.")
        payload = json.dumps({
            "model": db_get("model_" + ai_name, AI_DEFS[ai_name]["model_default"]),
            "messages": [{"role": "system", "content": system}, {"role": "user", "content": prompt}]
        }).encode()
        req = urllib.request.Request(
            "https://api.openai.com/v1/chat/completions", data=payload,
            headers={"Authorization": "Bearer " + key, "Content-Type": "application/json"}, method="POST")
        with urllib.request.urlopen(req, timeout=60) as r:
            return json.loads(r.read())["choices"][0]["message"]["content"]

    elif endpoint == "grok":
        if not key:
            raise ValueError("No xAI API key set. Go to Settings.")
        payload = json.dumps({
            "model": db_get("model_Grok", "grok-2-latest"),
            "messages": [{"role": "system", "content": system}, {"role": "user", "content": prompt}]
        }).encode()
        req = urllib.request.Request(
            "https://api.x.ai/v1/chat/completions", data=payload,
            headers={"Authorization": "Bearer " + key, "Content-Type": "application/json"}, method="POST")
        with urllib.request.urlopen(req, timeout=60) as r:
            return json.loads(r.read())["choices"][0]["message"]["content"]

    elif endpoint == "gemini":
        if not key:
            raise ValueError("No Google API key set. Go to Settings.")
        model = db_get("model_Gemini", "gemini-2.0-flash")
        payload = json.dumps({
            "contents": [{"parts": [{"text": prompt}]}],
            "system": {"parts": [{"text": system}]}
        }).encode()
        req = urllib.request.Request(
            "https://generativelanguage.googleapis.com/v1beta/models/" + model + ":generateContent?key=" + key,
            data=payload, headers={"Content-Type": "application/json"}, method="POST")
        with urllib.request.urlopen(req, timeout=60) as r:
            return json.loads(r.read())["candidates"][0]["content"]["parts"][0]["text"]

    elif endpoint == "lmstudio":
        model = db_get("model_Mistral", "qwen/qwen3-vl-32b")
        payload = json.dumps({
            "model": model,
            "messages": [{"role": "system", "content": system}, {"role": "user", "content": prompt}],
            "stream": False
        }).encode()
        req = urllib.request.Request(
            "http://localhost:1234/v1/chat/completions", data=payload,
            headers={"Content-Type": "application/json"}, method="POST")
        with urllib.request.urlopen(req, timeout=120) as r:
            return json.loads(r.read())["choices"][0]["message"]["content"]

    raise ValueError("Error: unsupported AI endpoint")

CSS = "\n@import url('https://fonts.googleapis.com/css2?family=Nunito:wght@400;700;900&display=swap');\n:root{--pink:#FF1493;--pink-light:#FFB6C1;--pink-pale:#FFF0F5;--white:#fff;--text:#1a1a1a;--muted:#999;--border:#FFB6C1}\n*{box-sizing:border-box;margin:0;padding:0}\nbody{background:var(--white);color:var(--text);font-family:'Nunito','Segoe UI',system-ui,sans-serif;height:100vh;display:flex;flex-direction:column;overflow:hidden}\nheader{background:var(--pink);padding:8px 16px;display:flex;align-items:center;gap:10px;border-bottom:3px solid #cc0070;flex-shrink:0}\nheader img{width:36px;height:36px;border-radius:50%;border:2px solid #fff}\nheader h1{color:#fff;font-size:1.6rem;font-weight:900;font-family:'Nunito','Segoe UI Black','Arial Black',sans-serif;letter-spacing:-1px}\n.ai-selector{margin-left:auto;display:flex;align-items:center;gap:8px}\n.ai-badge{background:rgba(255,255,255,0.2);border:2px solid rgba(255,255,255,0.5);color:#fff;padding:4px 14px;border-radius:20px;font-weight:700;font-size:.82rem;cursor:pointer}\n.ai-badge:hover{background:rgba(255,255,255,0.35)}\n.ai-dropdown{position:relative;display:inline-block}\n.ai-menu{display:none;position:absolute;top:110%;right:0;background:#fff;border:2px solid var(--pink);border-radius:12px;padding:6px;z-index:200;min-width:180px;box-shadow:4px 4px 0 var(--pink-light)}\n.ai-menu.open{display:block}\n.ai-item{padding:8px 14px;border-radius:8px;cursor:pointer;font-size:.84rem;font-weight:700;color:var(--text)}\n.ai-item:hover,.ai-item.active{background:var(--pink-pale);color:var(--pink)}\n.cats{display:flex;gap:6px;padding:8px 14px;background:var(--pink-pale);border-bottom:2px solid var(--pink-light);flex-wrap:wrap;flex-shrink:0}\n.cat-btn{background:#fff;border:2.5px solid var(--pink);color:#1a1a1a;padding:6px 16px;border-radius:24px;cursor:pointer;font-size:.84rem;font-weight:900;font-family:'Nunito','Segoe UI Black','Arial Black',sans-serif;text-transform:lowercase;transition:all .12s;box-shadow:2px 2px 0 var(--pink-light)}\n.cat-btn:hover,.cat-btn.active{background:var(--pink);color:#fff;box-shadow:2px 2px 0 #cc0070}\n.nav-tabs{display:flex;gap:4px;padding:6px 14px;background:var(--pink-pale);border-bottom:1px solid var(--pink-light);flex-shrink:0}\n.nav-tab{background:#fff;border:2px solid var(--pink-light);color:var(--muted);padding:4px 14px;border-radius:20px;cursor:pointer;font-size:.78rem;font-weight:700;transition:all .12s}\n.nav-tab:hover,.nav-tab.active{background:var(--pink);border-color:var(--pink);color:#fff}\n.workspace{flex:1;display:flex;overflow:hidden}\n.panel{display:none;flex:1;overflow:hidden}\n.panel.active{display:flex;position:relative}\n.left-col{flex:1;display:flex;flex-direction:column;overflow-y:auto;padding:12px 14px;gap:10px;border-right:2px solid var(--pink-light)}\n.icon-bar{display:flex;flex-direction:column;align-items:center;gap:6px;padding:10px 8px;background:var(--pink-pale);width:80px;flex-shrink:0}\n.icon-btn{background:#fff;border:2px solid var(--pink-light);border-radius:14px;width:62px;height:62px;cursor:pointer;display:flex;flex-direction:column;align-items:center;justify-content:center;gap:3px;transition:all .12s;padding:6px}\n.icon-btn:hover{border-color:var(--pink);background:var(--pink-pale);transform:scale(1.1);box-shadow:0 4px 12px rgba(255,20,147,.25)}\n.icon-btn img{width:42px;height:42px;object-fit:contain}\n.icon-btn span{font-size:.48rem;color:var(--pink);font-weight:900;text-align:center;line-height:1.1;font-family:'Nunito','Segoe UI Black',sans-serif}\n.icon-btn.rage-icon{border-color:#cc0000;background:#fff5f5}\n.icon-btn.rage-icon:hover{background:#ffe0e0;border-color:#ff0000;box-shadow:0 4px 12px rgba(200,0,0,.25)}\n.sdd-hdr{background:linear-gradient(135deg,#cc0070,var(--pink));color:#fff;padding:10px 14px;font-weight:900;font-family:'Nunito','Segoe UI Black',sans-serif;font-size:.85rem;display:flex;align-items:center;gap:8px;flex-shrink:0;letter-spacing:.02em}\n.sdd-body{flex:1;overflow-y:auto;padding:12px;display:flex;flex-direction:column;gap:8px}\n.sdd-empty{color:var(--muted);font-size:.82rem;text-align:center;padding:30px 20px;line-height:1.6}\n.sdd-chip-hdr{display:flex;align-items:center;gap:10px;margin-bottom:6px}\n.sdd-chip-icon{width:48px;height:48px;border-radius:12px;border:2px solid var(--pink)}\n.sdd-chip-name{font-size:1.4rem;font-weight:900;font-family:'Nunito','Segoe UI Black',sans-serif;color:var(--text);letter-spacing:.03em}\n.sdd-field{margin-bottom:6px}\n.sdd-field label{display:block;font-size:.72rem;font-weight:900;color:var(--pink);text-transform:uppercase;letter-spacing:.08em;margin-bottom:3px;font-family:'Nunito',sans-serif}\n.sdd-field input,.sdd-field textarea{width:100%;background:var(--pink-pale);border:2px solid var(--pink-light);color:var(--text);border-radius:8px;padding:7px 10px;font-size:.82rem;font-family:inherit;outline:none;transition:border .12s;resize:vertical}\n.sdd-field input:focus,.sdd-field textarea:focus{border-color:var(--pink)}\n.sdd-actions{display:flex;gap:6px;margin-top:8px;padding-top:8px;border-top:2px solid var(--pink-light)}\n.sdd-desc{font-size:.72rem;color:var(--muted);line-height:1.5;margin-bottom:8px;padding:8px;background:var(--pink-pale);border-radius:8px;border-left:3px solid var(--pink)}\n.right-col{width:380px;min-width:300px;display:flex;flex-direction:column;background:var(--pink-pale);flex-shrink:0;transition:width .2s}\n.right-col.hidden{display:none}\n.panel-full{flex:1;overflow-y:auto;padding:12px 14px;display:flex;flex-direction:column;gap:10px}\n.section{background:#fff;border:2px solid var(--pink-light);border-radius:14px;padding:12px}\n.sec-label{font-size:.68rem;font-weight:900;font-family:'Nunito','Segoe UI Black','Arial Black',sans-serif;color:var(--pink);letter-spacing:.08em;text-transform:uppercase;margin-bottom:8px;display:flex;justify-content:space-between}\n.chip-grid{display:flex;flex-wrap:wrap;gap:6px}\n.chip{background:#fff;border:2.5px solid var(--pink);color:#1a1a1a;padding:5px 12px;border-radius:18px;cursor:pointer;font-size:.78rem;font-weight:900;font-family:'Nunito','Segoe UI Black','Arial Black',sans-serif;text-transform:uppercase;transition:all .12s;box-shadow:2px 2px 0 var(--pink-light);user-select:none}\n.chip:hover{background:var(--pink);color:#fff;transform:translate(-1px,-1px);box-shadow:3px 3px 0 #cc0070}\n.chip.custom-chip{background:var(--pink);color:#fff;border-color:#cc0070}\n.chip.custom-chip:hover{background:#cc0070}\n.prompt-wrap{background:var(--pink-pale);border:2px solid var(--pink-light);border-radius:10px;padding:10px 12px;min-height:80px;cursor:text;font-size:.9rem;font-family:inherit;color:var(--text);line-height:1.8;outline:none;word-break:break-word}\n.prompt-wrap:focus{border-color:var(--pink)}\n.prompt-wrap:empty:before{content:attr(data-ph);color:#ccc;pointer-events:none}\n.ptag{display:inline-flex;align-items:center;gap:0;cursor:default;user-select:none;margin:0 2px;vertical-align:middle;border-radius:6px;overflow:hidden;border:2px solid var(--pink)}\n.ptag-label{background:var(--pink);color:#fff;padding:2px 8px;font-size:.75rem;font-weight:700;white-space:nowrap}\n.ptag-prompt{background:#1a1a1a;color:#fff;padding:2px 8px;font-size:.75rem;font-weight:400;white-space:nowrap;max-width:400px;overflow:hidden;text-overflow:ellipsis}\n.ptag .px{font-size:.65rem;opacity:.7;cursor:pointer;margin-left:2px}\n.ptag .px:hover{opacity:1}\n.btn-row{display:flex;gap:6px;margin-top:8px;flex-wrap:wrap;align-items:center}\n.btn{background:var(--pink);border:none;color:#fff;padding:8px 20px;border-radius:18px;font-size:.84rem;font-weight:900;font-family:'Nunito','Segoe UI Black','Arial Black',sans-serif;cursor:pointer;box-shadow:2px 2px 0 #cc0070;transition:all .12s}\n.btn:hover{background:#cc0070;transform:translate(-1px,-1px)}\n.btn:disabled{opacity:.4;cursor:not-allowed;transform:none}\n.btn-g{background:#fff;border:2px solid var(--pink);color:var(--pink);padding:7px 16px;border-radius:18px;font-size:.82rem;font-weight:700;cursor:pointer;transition:all .12s}\n.btn-g:hover{background:var(--pink);color:#fff}\n.dd-wrap{position:relative;display:inline-block}\n.dd-menu{display:none;position:absolute;top:110%;left:0;background:#fff;border:2px solid var(--pink);border-radius:10px;padding:5px;z-index:100;min-width:150px;box-shadow:4px 4px 0 var(--pink-light)}\n.dd-menu.open{display:block}\n.dd-item{padding:6px 12px;border-radius:6px;cursor:pointer;font-size:.8rem;font-weight:700;color:var(--pink)}\n.dd-item:hover{background:var(--pink-pale)}\n#status{font-size:.78rem;color:var(--muted)}\n.ai-win-hdr{background:var(--pink);color:#fff;padding:8px 14px;font-weight:900;font-family:'Nunito','Segoe UI Black','Arial Black',sans-serif;font-size:.82rem;display:flex;align-items:center;gap:8px;flex-shrink:0}\n.ai-win-body{flex:1;overflow-y:auto;padding:10px 12px;display:flex;flex-direction:column;gap:8px}\n.ai-msg{background:#fff;border:2px solid var(--pink-light);border-radius:12px;padding:10px 12px}\n.ai-msg-meta{font-size:.68rem;color:var(--muted);margin-bottom:5px;font-weight:700}\n.ai-msg-text{white-space:pre-wrap;font-family:'Consolas','Courier New',monospace;font-size:.8rem;line-height:1.6;color:var(--text)}\n.ai-msg-actions{display:flex;gap:5px;margin-top:7px}\n.ai-empty{color:var(--muted);font-size:.82rem;text-align:center;padding:30px 20px}\n.bsm{padding:3px 10px;border-radius:8px;font-size:.72rem;cursor:pointer;border:2px solid var(--pink-light);background:#fff;color:var(--pink);font-weight:700}\n.bsm:hover{border-color:var(--pink);background:var(--pink);color:#fff}\n.bdel:hover{border-color:#f44;background:#f44;color:#fff}\n.card{background:#fff;border:2px solid var(--pink-light);border-radius:12px;padding:12px;margin-bottom:8px}\nh3{color:var(--pink);font-size:.85rem;font-weight:900;font-family:'Nunito','Segoe UI Black','Arial Black',sans-serif;margin-bottom:8px;text-transform:uppercase;letter-spacing:.05em}\ninput,textarea,select{width:100%;background:var(--pink-pale);border:2px solid var(--pink-light);color:var(--text);border-radius:8px;padding:7px 10px;font-size:.85rem;font-family:inherit;outline:none;transition:border .12s;margin-bottom:6px}\ninput:focus,textarea:focus,select:focus{border-color:var(--pink)}\ntextarea{resize:vertical}\n.chain-card{background:#fff;border:2px solid var(--pink-light);border-radius:12px;padding:10px 12px;margin-bottom:7px}\n.chain-name{font-weight:900;font-size:.86rem;color:var(--text);margin-bottom:5px;display:flex;justify-content:space-between;align-items:center}\n.chain-chips{display:flex;flex-wrap:wrap;gap:4px;margin-bottom:6px}\n.chain-chip{background:var(--pink-pale);border:1px solid var(--pink-light);color:var(--pink);padding:2px 8px;border-radius:8px;font-size:.72rem;font-weight:700}\n.locked-badge{font-size:.65rem;background:var(--pink-pale);color:var(--pink);border:1px solid var(--pink-light);padding:2px 7px;border-radius:8px}\n.hi-item{border:2px solid var(--pink-light);border-radius:10px;padding:9px 12px;margin-bottom:6px;cursor:pointer}\n.hi-item:hover{border-color:var(--pink)}\n.hi-meta{color:var(--muted);font-size:.7rem;margin-bottom:3px}\n.hi-prompt{font-size:.82rem;font-weight:600;white-space:nowrap;overflow:hidden;text-overflow:ellipsis}\n.hi-resp{font-size:.78rem;color:#555;margin-top:5px;white-space:pre-wrap;display:none;max-height:150px;overflow-y:auto;font-family:monospace}\n.settings-group{background:#fff;border:2px solid var(--pink-light);border-radius:12px;padding:14px;margin-bottom:10px}\n.ai-setting{border:2px solid var(--pink-light);border-radius:10px;padding:10px 12px;margin-bottom:8px}\n.ai-setting-hdr{display:flex;align-items:center;gap:8px;margin-bottom:8px;font-weight:700;font-size:.88rem}\n#fluff-tip{position:fixed;background:#1a1a1a;color:#fff;font-size:.72rem;padding:6px 10px;border-radius:8px;max-width:280px;white-space:normal;z-index:99999;pointer-events:none;line-height:1.45;box-shadow:0 4px 16px rgba(0,0,0,.35);display:none}\n"

JS = '\nconst FLUFFY = FLUFFY_JSON;\nconst AI_DEFS = AI_DEFS_JSON;\nconst DEFAULT_CHAINS = DEFAULT_CHAINS_JSON;\nlet curCat = \'software\';\nlet responses = [];\nlet activeAI = \'Claude\';\n\n// Audio\nconst actx = new (window.AudioContext||window.webkitAudioContext)();\nfunction playClick(){\n  try {\n    const o=actx.createOscillator(),g=actx.createGain();\n    o.connect(g);g.connect(actx.destination);\n    o.type=\'square\';\n    o.frequency.setValueAtTime(880,actx.currentTime);\n    o.frequency.exponentialRampToValueAtTime(180,actx.currentTime+0.045);\n    g.gain.setValueAtTime(0.25,actx.currentTime);\n    g.gain.exponentialRampToValueAtTime(0.001,actx.currentTime+0.05);\n    o.start();o.stop(actx.currentTime+0.05);\n  } catch(e){}\n}\nfunction playMunch(){ try{ new Audio(\'/sound/munch\').play(); }catch(e){} }\n\n// Init\n(async function init(){\n  const s = await(await fetch(\'/api/settings\')).json();\n  activeAI = s.active_ai || \'Claude\';\n  buildAIMenu();\n  buildSendToMenu();\n  buildAISettings(s);\n  await loadCat(\'software\');\n  playMunch();\n})();\n\n// AI Menu\nfunction buildAIMenu(){\n  const m = document.getElementById(\'ai-menu\');\n  m.innerHTML = \'\';\n  Object.entries(AI_DEFS).forEach(function(entry){\n    const k = entry[0], v = entry[1];\n    const d = document.createElement(\'div\');\n    d.className = \'ai-item\' + (k===activeAI?\' active\':\'\');\n    d.textContent = v.emoji + \' \' + v.label;\n    d.onclick = function(){ setActiveAI(k); };\n    m.appendChild(d);\n  });\n}\n\nfunction buildSendToMenu(){\n  const m = document.getElementById(\'sendto-menu\');\n  m.innerHTML = \'\';\n  Object.entries(AI_DEFS).forEach(function(entry){\n    const k = entry[0], v = entry[1];\n    const d = document.createElement(\'div\');\n    d.className = \'dd-item\';\n    d.textContent = v.emoji + \' \' + v.label;\n    d.onclick = function(){ toggleDD(\'sendto-menu\'); sendToAI(k); };\n    m.appendChild(d);\n  });\n}\n\nfunction toggleAIMenu(){ document.getElementById(\'ai-menu\').classList.toggle(\'open\'); }\n\nasync function setActiveAI(name){\n  activeAI = name;\n  const def = AI_DEFS[name] || {};\n  document.getElementById(\'ai-badge\').textContent = def.emoji + \' \' + def.label;\n  document.getElementById(\'ai-win-label\').textContent = def.label;\n  document.getElementById(\'ai-menu\').classList.remove(\'open\');\n  buildAIMenu();\n  await fetch(\'/api/settings\',{method:\'POST\',headers:{\'Content-Type\':\'application/json\'},\n    body:JSON.stringify({active_ai:name})});\n  playClick();\n}\n\ndocument.addEventListener(\'click\', function(e){\n  if(!e.target.closest(\'.ai-dropdown\')) document.getElementById(\'ai-menu\').classList.remove(\'open\');\n  if(!e.target.closest(\'.dd-wrap\')) document.querySelectorAll(\'.dd-menu\').forEach(function(m){ m.classList.remove(\'open\'); });\n});\n\n// Category\nasync function setCat(cat, btn){\n  curCat = cat;\n  document.querySelectorAll(\'.cat-btn\').forEach(function(b){ b.classList.remove(\'active\'); });\n  btn.classList.add(\'active\');\n  await loadCat(cat);\n  playClick();\n}\n\nasync function loadCat(cat){\n  const fg = document.getElementById(\'fluffy-grid\');\n  fg.innerHTML = \'\';\n  const chips = FLUFFY[cat] || [];\n  chips.forEach(function(item){\n    fg.appendChild(mkChip(item[0], item[1], false));\n  });\n  await loadCustomChips(cat);\n}\n\nasync function loadCustomChips(cat){\n  const cg = document.getElementById(\'custom-grid\');\n  cg.innerHTML = \'\';\n  const d = await(await fetch(\'/api/chips?cat=\'+encodeURIComponent(cat))).json();\n  d.forEach(function(c){ cg.appendChild(mkChip(c.label, c.prompt_text, true)); });\n}\n\nfunction mkChip(label, pt, isCustom){\n  const b = document.createElement(\'button\');\n  b.className = \'chip\' + (isCustom ? \' custom-chip\' : \'\');\n  b.textContent = label;\n  b.dataset.tip = pt.substring(0, 100);\n  b.onclick = function(){ insertChip(label, pt); };\n  return b;\n}\n\n// Tooltip\nconst tipEl = document.getElementById(\'fluff-tip\');\ndocument.addEventListener(\'mouseover\', function(e){\n  const el = e.target.closest(\'.chip\');\n  if(el && el.dataset.tip){ tipEl.textContent = el.dataset.tip; tipEl.style.display = \'block\'; }\n  else { tipEl.style.display = \'none\'; }\n});\ndocument.addEventListener(\'mousemove\', function(e){\n  if(tipEl.style.display === \'block\'){\n    let x = e.clientX + 14, y = e.clientY + 14;\n    if(x + 300 > window.innerWidth) x = e.clientX - 310;\n    if(y + 50 > window.innerHeight) y = e.clientY - 55;\n    tipEl.style.left = x + \'px\';\n    tipEl.style.top = y + \'px\';\n  }\n});\ndocument.addEventListener(\'mouseout\', function(e){\n  if(!e.target.closest(\'.chip\')) tipEl.style.display = \'none\';\n});\n\n// Inline chip insertion\nfunction insertChip(label, pt){\n  const wrap = document.getElementById(\'pwrap\');\n  wrap.focus();\n  const chip = document.createElement(\'span\');\n  chip.className = \'ptag\';\n  chip.contentEditable = \'false\';\n  chip.dataset.pt = pt;\n  const labelSpan = document.createElement(\'span\');\n  labelSpan.className = \'ptag-label\';\n  labelSpan.textContent = label;\n  const promptSpan = document.createElement(\'span\');\n  promptSpan.className = \'ptag-prompt\';\n  promptSpan.textContent = pt;\n  const xSpan = document.createElement(\'span\');\n  xSpan.className = \'px\';\n  xSpan.textContent = \'x\';\n  xSpan.onclick = function(){ chip.remove(); playClick(); };\n  chip.appendChild(labelSpan);\n  chip.appendChild(promptSpan);\n  chip.appendChild(xSpan);\n  const sel = window.getSelection();\n  if(sel && sel.rangeCount && wrap.contains(sel.anchorNode)){\n    const r = sel.getRangeAt(0);\n    r.deleteContents();\n    r.insertNode(chip);\n    r.setStartAfter(chip); r.collapse(true);\n    sel.removeAllRanges(); sel.addRange(r);\n    const sp = document.createTextNode(\' \');\n    r.insertNode(sp); r.setStartAfter(sp); r.collapse(true);\n    sel.removeAllRanges(); sel.addRange(r);\n  } else {\n    wrap.appendChild(chip);\n    wrap.appendChild(document.createTextNode(\' \'));\n  }\n  openSpec(label, pt);\n  playClick();\n}\n\nfunction buildPrompt(){\n  const wrap = document.getElementById(\'pwrap\');\n  let t = \'\';\n  wrap.childNodes.forEach(function(n){\n    if(n.nodeType === Node.TEXT_NODE) t += n.textContent;\n    else if(n.classList && n.classList.contains(\'ptag\'))\n      t += \' \' + (n.dataset.pt || \'\') + \' \';\n  });\n  return t.replace(/\\s+/g,\' \').trim();\n}\n\n// Send\nasync function sendPrompt(){ await sendToAI(activeAI); }\n\nasync function sendToAI(aiName){\n  const p = buildPrompt();\n  if(!p){ alert(\'Add something to your prompt first.\'); return; }\n  const st = document.getElementById(\'status\');\n  const btn = document.getElementById(\'sendbtn\');\n  const def = AI_DEFS[aiName] || {};\n  st.textContent = \'Sending to \' + (def.label || aiName) + \'...\';\n  btn.disabled = true;\n  const thinking = addAIMsg(\'Thinking...\', aiName, true);\n  try{\n    const r = await fetch(\'/api/prompt\',{method:\'POST\',headers:{\'Content-Type\':\'application/json\'},\n      body:JSON.stringify({ai:aiName, category:curCat, prompt:p})});\n    const d = await r.json();\n    if(d.error) throw new Error(d.error);\n    thinking.remove();\n    addAIMsg(d.response, aiName, false);\n    st.textContent = \'Done\';\n  } catch(e){\n    thinking.remove();\n    addAIMsg(\'Error: \' + e.message, aiName, false);\n    st.textContent = \'Error: \' + e.message;\n  }\n  btn.disabled = false;\n}\n\nfunction addAIMsg(text, aiName, isThinking){\n  const body = document.getElementById(\'ai-win-body\');\n  const empty = body.querySelector(\'.ai-empty\');\n  if(empty) empty.remove();\n  const def = AI_DEFS[aiName] || {};\n  const msg = document.createElement(\'div\');\n  msg.className = \'ai-msg\';\n  if(isThinking){ msg.style.opacity = \'0.5\'; msg.style.fontStyle = \'italic\'; }\n  msg.dataset.raw = text;\n  const now = new Date().toLocaleTimeString();\n  const meta = document.createElement(\'div\');\n  meta.className = \'ai-msg-meta\';\n  meta.textContent = (def.emoji||\'\') + \' \' + (def.label||aiName) + \' - \' + now;\n  const content = document.createElement(\'div\');\n  content.className = \'ai-msg-text\';\n  content.textContent = text;\n  msg.appendChild(meta);\n  msg.appendChild(content);\n  if(!isThinking){\n    const actions = document.createElement(\'div\');\n    actions.className = \'ai-msg-actions\';\n    const copyBtn = document.createElement(\'button\');\n    copyBtn.className = \'bsm\';\n    copyBtn.textContent = \'Copy\';\n    copyBtn.onclick = function(){ cpMsg(copyBtn); };\n    const pinBtn = document.createElement(\'button\');\n    pinBtn.className = \'bsm\';\n    pinBtn.textContent = \'Pin Chip\';\n    pinBtn.onclick = function(){ pinMsg(pinBtn); };\n    const delBtn = document.createElement(\'button\');\n    delBtn.className = \'bsm bdel\';\n    delBtn.textContent = \'X\';\n    delBtn.onclick = function(){ msg.remove(); };\n    actions.appendChild(copyBtn);\n    actions.appendChild(pinBtn);\n    actions.appendChild(delBtn);\n    msg.appendChild(actions);\n  }\n  body.appendChild(msg);\n  body.scrollTop = body.scrollHeight;\n  return msg;\n}\n\nfunction cpMsg(btn){\n  const t = btn.closest(\'.ai-msg\').dataset.raw || \'\';\n  navigator.clipboard.writeText(t).then(function(){\n    btn.textContent = \'Copied!\';\n    setTimeout(function(){ btn.textContent = \'Copy\'; }, 1500);\n  });\n  playClick();\n}\n\nasync function pinMsg(btn){\n  const t = btn.closest(\'.ai-msg\').dataset.raw || \'\';\n  const label = window.prompt(\'Chip label?\');\n  if(!label) return;\n  await fetch(\'/api/chips\',{method:\'POST\',headers:{\'Content-Type\':\'application/json\'},\n    body:JSON.stringify({category:curCat, label:label, prompt_text:t})});\n  loadCustomChips(curCat);\n  playClick();\n}\n\nfunction toggleChat(){\n  const rc = document.querySelector(\'.right-col\');\n  rc.classList.toggle(\'hidden\');\n  const btn = document.getElementById(\'chat-toggle\');\n  if(btn) btn.textContent = rc.classList.contains(\'hidden\') ? \'Show Spec\' : \'Hide Spec\';\n}\n\nfunction toggleChat(){\n  const rc = document.querySelector(\'.right-col\');\n  rc.classList.toggle(\'hidden\');\n  const btn = document.getElementById(\'chat-toggle\');\n  if(btn) btn.textContent = rc.classList.contains(\'hidden\') ? \'Show Spec\' : \'Hide Spec\';\n}\n\nfunction clearAIWin(){\n  const body = document.getElementById(\'ai-win-body\');\n  body.innerHTML = \'\';\n  const empty = document.createElement(\'div\');\n  empty.className = \'ai-empty\';\n  empty.textContent = \'Send a prompt to see responses here.\';\n  body.appendChild(empty);\n  responses = [];\n  playClick();\n}\n\nfunction copyAll(){\n  const p = buildPrompt();\n  if(!p){ alert(\'Nothing to copy.\'); return; }\n  navigator.clipboard.writeText(p).then(function(){\n    document.getElementById(\'status\').textContent = \'Copied!\';\n    playClick();\n  });\n}\n\nfunction clearPrompt(){\n  document.getElementById(\'pwrap\').innerHTML = \'\';\n  document.getElementById(\'status\').textContent = \'\';\n  playClick();\n}\n\n// RAGE\nasync function sendRage(){\n  const p = buildPrompt();\n  if(!p){ alert(\'Add a prompt first.\'); return; }\n  const st = document.getElementById(\'status\');\n  const btn = document.getElementById(\'ragebtn\');\n  st.textContent = \'Gumnuts is not impressed...\';\n  if(btn) btn.disabled = true;\n  const thinking = addAIMsg(\'Sending again - properly this time...\', activeAI, true);\n  try{\n    const r = await fetch(\'/api/rage\',{method:\'POST\',headers:{\'Content-Type\':\'application/json\'},\n      body:JSON.stringify({ai:activeAI, category:curCat, prompt:p})});\n    const d = await r.json();\n    if(d.error) throw new Error(d.error);\n    thinking.remove();\n    addAIMsg(d.response, activeAI, false);\n    st.textContent = \'Done. Better.\';\n  } catch(e){\n    thinking.remove();\n    addAIMsg(\'Error: \' + e.message, activeAI, false);\n    st.textContent = \'Error: \' + e.message;\n  }\n  if(btn) btn.disabled = false;\n}\n\n// Icon bar\nasync function loadMemory(){\n  const d = await(await fetch(\'/api/chips?cat=\'+encodeURIComponent(curCat))).json();\n  if(!d.length){ addAIMsg(\'No saved chips for this category yet.\', activeAI, true); return; }\n  const list = d.map(function(c){ return c.label + \': \' + c.prompt_text; }).join(\' | \');\n  addAIMsg(\'Loaded \' + d.length + \' chips for \' + curCat + \': \' + list, activeAI, false);\n  playClick();\n}\n\nasync function summariseAI(){\n  const msgs = document.querySelectorAll(\'.ai-msg-text\');\n  if(!msgs.length){ alert(\'No responses to summarise yet.\'); return; }\n  const combined = Array.from(msgs).map(function(m){ return m.textContent; }).join(\' --- \');\n  const p = \'Summarise the key points from these AI responses concisely: \' + combined;\n  const st = document.getElementById(\'status\');\n  st.textContent = \'Summarising...\';\n  try{\n    const r = await fetch(\'/api/prompt\',{method:\'POST\',headers:{\'Content-Type\':\'application/json\'},\n      body:JSON.stringify({ai:activeAI, category:curCat, prompt:p})});\n    const d = await r.json();\n    if(d.error) throw new Error(d.error);\n    addAIMsg(\'SUMMARY: \' + d.response, activeAI, false);\n    st.textContent = \'Done\';\n  } catch(e){ st.textContent = \'Error: \' + e.message; }\n  playClick();\n}\n\nasync function sendToAll(){\n  const p = buildPrompt();\n  if(!p){ alert(\'Add a prompt first.\'); return; }\n  document.getElementById(\'status\').textContent = \'Sending to all AIs...\';\n  const ais = Object.keys(AI_DEFS);\n  for(let i = 0; i < ais.length; i++){\n    const ai = ais[i];\n    const thinking = addAIMsg(\'Sending to \' + AI_DEFS[ai].label + \'...\', ai, true);\n    try{\n      const r = await fetch(\'/api/prompt\',{method:\'POST\',headers:{\'Content-Type\':\'application/json\'},\n        body:JSON.stringify({ai:ai, category:curCat, prompt:p})});\n      const d = await r.json();\n      thinking.remove();\n      if(d.error) addAIMsg(\'Error: \' + d.error, ai, false);\n      else addAIMsg(d.response, ai, false);\n    } catch(e){\n      thinking.remove();\n      addAIMsg(\'Error: \' + e.message, ai, false);\n    }\n  }\n  document.getElementById(\'status\').textContent = \'All done\';\n  playClick();\n}\n\nfunction saveSession(){\n  const msgs = Array.from(document.querySelectorAll(\'.ai-msg\')).map(function(m){\n    const meta = m.querySelector(\'.ai-msg-meta\');\n    return { ai: meta ? meta.textContent : \'\', text: m.dataset.raw || \'\' };\n  });\n  const data = {\n    exported: new Date().toISOString(),\n    category: curCat,\n    activeAI: activeAI,\n    prompt: buildPrompt(),\n    messages: msgs\n  };\n  const blob = new Blob([JSON.stringify(data, null, 2)], {type:\'application/json\'});\n  const a = document.createElement(\'a\');\n  a.href = URL.createObjectURL(blob);\n  a.download = \'fluffnuts-\' + new Date().toISOString().substring(0,10) + \'.json\';\n  a.click();\n  playClick();\n}\n\n// Chains\nasync function saveChain(){\n  const wrap = document.getElementById(\'pwrap\');\n  const chips = [];\n  wrap.childNodes.forEach(function(n){\n    if(n.classList && n.classList.contains(\'ptag\'))\n      chips.push({label: n.querySelector(\'.px\') ? n.textContent.replace(\'x\',\'\').trim() : n.textContent.trim(), promptText: n.dataset.pt || \'\'});\n  });\n  if(!chips.length){ alert(\'Add some chips to your prompt first.\'); return; }\n  const name = window.prompt(\'Chain name?\');\n  if(!name) return;\n  await fetch(\'/api/chains\',{method:\'POST\',headers:{\'Content-Type\':\'application/json\'},\n    body:JSON.stringify({name:name, category:curCat, chips:JSON.stringify(chips)})});\n  alert(\'Chain saved!\');\n  playClick();\n}\n\nasync function loadChainsList(){\n  const d = await(await fetch(\'/api/chains\')).json();\n  const el = document.getElementById(\'chains-list\');\n  el.innerHTML = \'\';\n  const defaults = DEFAULT_CHAINS[curCat] || [];\n  if(defaults.length){\n    const hdr = document.createElement(\'h3\');\n    hdr.textContent = \'FluffyChains\';\n    el.appendChild(hdr);\n    defaults.forEach(function(c){ el.appendChild(mkChainCard(c.name, curCat, c.chips, true, null)); });\n  }\n  const userChains = d.filter(function(c){ return c.category === curCat; });\n  if(userChains.length){\n    const hdr = document.createElement(\'h3\');\n    hdr.style.marginTop = \'12px\';\n    hdr.textContent = \'Your Chains\';\n    el.appendChild(hdr);\n    userChains.forEach(function(c){\n      el.appendChild(mkChainCard(c.name, c.category, JSON.parse(c.chips||\'[]\'), false, c.id));\n    });\n  }\n  if(!defaults.length && !userChains.length){\n    el.innerHTML = \'<p style="color:#aaa;font-size:.82rem">No chains yet. Build a prompt with chips then hit Save Chain.</p>\';\n  }\n}\n\nfunction mkChainCard(name, cat, chips, isLocked, id){\n  const div = document.createElement(\'div\');\n  div.className = \'chain-card\';\n  const nameDiv = document.createElement(\'div\');\n  nameDiv.className = \'chain-name\';\n  nameDiv.textContent = name;\n  const badge = document.createElement(\'span\');\n  badge.className = \'locked-badge\';\n  badge.textContent = isLocked ? \'default\' : \'custom\';\n  nameDiv.appendChild(badge);\n  const chipsDiv = document.createElement(\'div\');\n  chipsDiv.className = \'chain-chips\';\n  chips.forEach(function(c){\n    const sp = document.createElement(\'span\');\n    sp.className = \'chain-chip\';\n    sp.textContent = c.label || c;\n    chipsDiv.appendChild(sp);\n  });\n  const actDiv = document.createElement(\'div\');\n  const loadBtn = document.createElement(\'button\');\n  loadBtn.className = \'bsm\';\n  loadBtn.textContent = \'Load\';\n  loadBtn.onclick = function(){ loadChain(chips); };\n  actDiv.appendChild(loadBtn);\n  if(!isLocked && id){\n    const delBtn = document.createElement(\'button\');\n    delBtn.className = \'bsm bdel\';\n    delBtn.textContent = \'Delete\';\n    delBtn.onclick = function(){ delChain(id); };\n    actDiv.appendChild(delBtn);\n  }\n  div.appendChild(nameDiv);\n  div.appendChild(chipsDiv);\n  div.appendChild(actDiv);\n  return div;\n}\n\nfunction loadChain(chips){\n  const wrap = document.getElementById(\'pwrap\');\n  wrap.innerHTML = \'\';\n  chips.forEach(function(c){ insertChip(c.label||c, c.promptText||c.label||c); });\n  showPanel(\'prompt\', document.querySelector(\'.nav-tab\'));\n  playClick();\n}\n\nasync function delChain(id){\n  if(!confirm(\'Delete chain?\')) return;\n  await fetch(\'/api/chains/\'+id,{method:\'DELETE\'});\n  loadChainsList();\n  playClick();\n}\n\n// History\nasync function loadHistory(){\n  const d = await(await fetch(\'/api/history\')).json();\n  const el = document.getElementById(\'history-list\');\n  el.innerHTML = d.length ? \'\' : \'<p style="color:#aaa">No history yet.</p>\';\n  d.forEach(function(h){\n    const div = document.createElement(\'div\');\n    div.className = \'hi-item\';\n    const meta = document.createElement(\'div\');\n    meta.className = \'hi-meta\';\n    meta.textContent = h.ts.substring(0,19).replace(\'T\',\' \') + \' - \' + (h.ai_name||\'Claude\') + \' - \' + h.category;\n    const prompt = document.createElement(\'div\');\n    prompt.className = \'hi-prompt\';\n    prompt.textContent = h.prompt;\n    const resp = document.createElement(\'div\');\n    resp.className = \'hi-resp\';\n    resp.textContent = h.response;\n    div.appendChild(meta);\n    div.appendChild(prompt);\n    div.appendChild(resp);\n    div.onclick = function(){ resp.style.display = resp.style.display === \'block\' ? \'none\' : \'block\'; };\n    el.appendChild(div);\n  });\n}\n\n// Chips panel\nasync function loadChipsPanel(){\n  const fg = document.getElementById(\'all-fluffy-grid\');\n  fg.innerHTML = \'\';\n  const countEl = document.getElementById(\'fluffy-count\');\n  if(countEl) countEl.textContent = curCat;\n  const chips = FLUFFY[curCat] || [];\n  chips.forEach(function(item){\n    const b = document.createElement(\'button\');\n    b.className = \'chip\';\n    b.textContent = item[0];\n    b.dataset.tip = item[1];\n    b.onclick = function(){\n      insertChip(item[0], item[1]);\n      showPanel(\'prompt\', document.querySelector(\'.nav-tab\'));\n    };\n    fg.appendChild(b);\n  });\n  const d = await(await fetch(\'/api/chips\')).json();\n  const el = document.getElementById(\'custom-chip-list\');\n  el.innerHTML = d.length ? \'\' : \'<p style="color:#aaa">None yet.</p>\';\n  d.forEach(function(c){\n    const div = document.createElement(\'div\');\n    div.className = \'chain-card\';\n    const nameDiv = document.createElement(\'div\');\n    nameDiv.className = \'chain-name\';\n    nameDiv.textContent = c.label;\n    const badge = document.createElement(\'span\');\n    badge.className = \'locked-badge\';\n    badge.textContent = c.category;\n    nameDiv.appendChild(badge);\n    const pt = document.createElement(\'div\');\n    pt.style.cssText = \'font-size:.78rem;color:#777;margin-bottom:6px\';\n    pt.textContent = c.prompt_text;\n    const delBtn = document.createElement(\'button\');\n    delBtn.className = \'bsm bdel\';\n    delBtn.textContent = \'Delete\';\n    delBtn.onclick = function(){ delChip(c.id); };\n    div.appendChild(nameDiv);\n    div.appendChild(pt);\n    div.appendChild(delBtn);\n    el.appendChild(div);\n  });\n}\n\nasync function addCustomChip(){\n  const cat = document.getElementById(\'cc-cat\').value;\n  const label = document.getElementById(\'cc-label\').value.trim();\n  const pt = document.getElementById(\'cc-text\').value.trim();\n  if(!label||!pt){ alert(\'Label and prompt text required.\'); return; }\n  await fetch(\'/api/chips\',{method:\'POST\',headers:{\'Content-Type\':\'application/json\'},\n    body:JSON.stringify({category:cat, label:label, prompt_text:pt})});\n  document.getElementById(\'cc-label\').value = \'\';\n  document.getElementById(\'cc-text\').value = \'\';\n  loadChipsPanel();\n  loadCustomChips(curCat);\n  playClick();\n}\n\nasync function delChip(id){\n  if(!confirm(\'Delete chip?\')) return;\n  await fetch(\'/api/chips/\'+id,{method:\'DELETE\'});\n  loadChipsPanel();\n  loadCustomChips(curCat);\n  playClick();\n}\n\n// Settings\nfunction buildAISettings(settings){\n  const el = document.getElementById(\'ai-settings-list\');\n  el.innerHTML = \'\';\n  Object.entries(AI_DEFS).forEach(function(entry){\n    const k = entry[0], v = entry[1];\n    const isOllama = v.endpoint === \'lmstudio\';\n    const div = document.createElement(\'div\');\n    div.className = \'ai-setting\';\n    const hdr = document.createElement(\'div\');\n    hdr.className = \'ai-setting-hdr\';\n    hdr.textContent = v.emoji + \' \' + v.label;\n    const setBtn = document.createElement(\'button\');\n    setBtn.className = \'bsm\';\n    setBtn.style.marginLeft = \'auto\';\n    setBtn.textContent = \'Set Active\';\n    setBtn.onclick = function(){ setActiveAI(k); };\n    hdr.appendChild(setBtn);\n    const keyLabel = document.createElement(\'label\');\n    keyLabel.style.cssText = \'font-size:.75rem;color:var(--muted)\';\n    keyLabel.textContent = v.key_label;\n    const keyInput = document.createElement(\'input\');\n    keyInput.type = isOllama ? \'text\' : \'password\';\n    keyInput.id = \'key-\' + k;\n    keyInput.placeholder = isOllama ? \'No key needed - uses LM Studio localhost:1234\' : v.key_hint;\n    keyInput.value = settings[\'key_\'+k] || \'\';\n    if(isOllama) keyInput.disabled = true;\n    const modelLabel = document.createElement(\'label\');\n    modelLabel.style.cssText = \'font-size:.75rem;color:var(--muted)\';\n    modelLabel.textContent = \'Model\';\n    const modelInput = document.createElement(\'input\');\n    modelInput.type = \'text\';\n    modelInput.id = \'model-\' + k;\n    modelInput.placeholder = v.model_default;\n    modelInput.value = settings[\'model_\'+k] || v.model_default;\n    const saveBtn = document.createElement(\'button\');\n    saveBtn.className = \'bsm\';\n    saveBtn.textContent = \'Save\';\n    saveBtn.onclick = function(){ saveAISettings(k); };\n    div.appendChild(hdr);\n    div.appendChild(keyLabel);\n    div.appendChild(keyInput);\n    div.appendChild(modelLabel);\n    div.appendChild(modelInput);\n    div.appendChild(saveBtn);\n    el.appendChild(div);\n  });\n}\n\nasync function saveAISettings(k){\n  const payload = {};\n  const keyEl = document.getElementById(\'key-\'+k);\n  const modelEl = document.getElementById(\'model-\'+k);\n  if(keyEl && !keyEl.disabled) payload[\'key_\'+k] = keyEl.value;\n  if(modelEl) payload[\'model_\'+k] = modelEl.value;\n  await fetch(\'/api/settings\',{method:\'POST\',headers:{\'Content-Type\':\'application/json\'},body:JSON.stringify(payload)});\n  alert(\'Saved!\');\n  playClick();\n}\n\n// Panels\nfunction showPanel(name, btn){\n  document.querySelectorAll(\'.panel\').forEach(function(p){ p.classList.remove(\'active\'); });\n  const panel = document.getElementById(\'panel-\'+name);\n  if(panel) panel.classList.add(\'active\');\n  document.querySelectorAll(\'.nav-tab\').forEach(function(b){ b.classList.remove(\'active\'); });\n  if(btn && btn.classList.contains(\'nav-tab\')) btn.classList.add(\'active\');\n  if(name === \'chains\') loadChainsList();\n  if(name === \'history\') loadHistory();\n  if(name === \'chips\') loadChipsPanel();\n  playClick();\n}\n\nfunction toggleDD(id){ document.getElementById(id).classList.toggle(\'open\'); }\n\nfunction esc(t){\n  return (t||\'\').replace(/&/g,\'&amp;\').replace(/</g,\'&lt;\').replace(/>/g,\'&gt;\');\n}\n\n// SDD - Spec-Driven Development\nfunction openSpec(label, promptText){\n  var rc = document.querySelector(\'.right-col\');\n  rc.classList.remove(\'hidden\');\n  var btn = document.getElementById(\'chat-toggle\');\n  if(btn){ var sp = btn.querySelector(\'span\'); if(sp) sp.textContent = \'Hide Spec\'; }\n  document.getElementById(\'sdd-empty\').style.display = \'none\';\n  document.getElementById(\'sdd-form\').style.display = \'block\';\n  document.getElementById(\'sdd-chip-name\').textContent = label;\n  document.getElementById(\'sdd-desc\').textContent = promptText;\n  document.getElementById(\'sdd-objective\').value = promptText;\n  document.getElementById(\'sdd-target\').value = \'\';\n  document.getElementById(\'sdd-context\').value = \'\';\n  document.getElementById(\'sdd-requirements\').value = \'\';\n  document.getElementById(\'sdd-constraints\').value = \'\';\n  document.getElementById(\'sdd-criteria\').value = \'\';\n  document.getElementById(\'sdd-target\').focus();\n  playClick();\n}\n\nfunction buildSpecPrompt(){\n  var label = document.getElementById(\'sdd-chip-name\').textContent;\n  var obj = document.getElementById(\'sdd-objective\').value.trim();\n  var target = document.getElementById(\'sdd-target\').value.trim();\n  var ctx = document.getElementById(\'sdd-context\').value.trim();\n  var reqs = document.getElementById(\'sdd-requirements\').value.trim();\n  var cons = document.getElementById(\'sdd-constraints\').value.trim();\n  var crit = document.getElementById(\'sdd-criteria\').value.trim();\n  if(!obj && !target){ alert(\'Fill in at least the objective and target.\'); return; }\n  var nl = \'\\n\';\n  var spec = \'## SPEC: \' + label + nl + nl;\n  spec += \'**Objective:** \' + obj + nl + nl;\n  if(target) spec += \'**Target:** \' + target + nl + nl;\n  if(ctx) spec += \'**Context:**\' + nl + ctx + nl + nl;\n  if(reqs) spec += \'**Requirements:**\' + nl + reqs + nl + nl;\n  if(cons) spec += \'**Constraints:**\' + nl + cons + nl + nl;\n  if(crit) spec += \'**Acceptance Criteria:**\' + nl + crit + nl + nl;\n  var wrap = document.getElementById(\'pwrap\');\n  wrap.textContent = spec;\n  document.getElementById(\'status\').textContent = \'Spec built - ready to send!\';\n  playClick();\n}\n\nfunction copySpecPrompt(){\n  var label = document.getElementById(\'sdd-chip-name\').textContent;\n  var obj = document.getElementById(\'sdd-objective\').value.trim();\n  var target = document.getElementById(\'sdd-target\').value.trim();\n  var ctx = document.getElementById(\'sdd-context\').value.trim();\n  var reqs = document.getElementById(\'sdd-requirements\').value.trim();\n  var cons = document.getElementById(\'sdd-constraints\').value.trim();\n  var crit = document.getElementById(\'sdd-criteria\').value.trim();\n  var nl = \'\\n\';\n  var spec = \'## SPEC: \' + label + nl + nl;\n  spec += \'**Objective:** \' + obj + nl + nl;\n  if(target) spec += \'**Target:** \' + target + nl + nl;\n  if(ctx) spec += \'**Context:**\' + nl + ctx + nl + nl;\n  if(reqs) spec += \'**Requirements:**\' + nl + reqs + nl + nl;\n  if(cons) spec += \'**Constraints:**\' + nl + cons + nl + nl;\n  if(crit) spec += \'**Acceptance Criteria:**\' + nl + crit + nl + nl;\n  navigator.clipboard.writeText(spec).then(function(){\n    document.getElementById(\'status\').textContent = \'Spec copied to clipboard!\';\n    playClick();\n  });\n}\n\nfunction clearSpec(){\n  document.getElementById(\'sdd-form\').style.display = \'none\';\n  document.getElementById(\'sdd-empty\').style.display = \'block\';\n  document.getElementById(\'sdd-objective\').value = \'\';\n  document.getElementById(\'sdd-target\').value = \'\';\n  document.getElementById(\'sdd-context\').value = \'\';\n  document.getElementById(\'sdd-requirements\').value = \'\';\n  document.getElementById(\'sdd-constraints\').value = \'\';\n  document.getElementById(\'sdd-criteria\').value = \'\';\n  playClick();\n}\n\n'

def build_html(fluffy_json, ai_defs_json, default_chains_json, cat_options):
    js = JS.replace("FLUFFY_JSON", fluffy_json).replace("AI_DEFS_JSON", ai_defs_json).replace("DEFAULT_CHAINS_JSON", default_chains_json)
