def get_app():
    from flask import Flask, request, jsonify, Response
    import sys
    app = Flask(__name__)
    app_dir = Path(sys.executable).parent if getattr(sys, 'frozen', False) else Path(__file__).parent

    @app.route('/koala')
    def koala():
        p = app_dir / 'FluffnutsPro_logo.png'
        if p.exists():
            return Response(p.read_bytes(), content_type='image/png')
        return '', 404

    @app.route('/favicon.ico')
    def favicon():
        p = app_dir / 'Fluffnutspro.ico'
        if p.exists():
            return Response(p.read_bytes(), content_type='image/x-icon')
        return '', 404

    @app.route('/icon/<n>')
    def icon(n):
        import base64
        if n in ICON_DATA:
            return Response(base64.b64decode(ICON_DATA[n]), content_type='image/png')
        p = app_dir / (n + '.png')
        if p.exists():
            return Response(p.read_bytes(), content_type='image/png')
        return '', 404

    @app.route('/sound/munch')
    def sound_munch():
        p = app_dir / 'munch.wav'
        if p.exists():
            return Response(p.read_bytes(), content_type='audio/wav')
        return '', 404

    @app.route('/treehouse')
    def treehouse():
        p = app_dir / 'treehouse.html'
        if p.exists():
            return Response(p.read_bytes(), content_type='text/html')
        return '', 404

    @app.route('/')
    def index():
        cat_options = ''.join('<option value="' + cat["name"] + '">' + cat["name"] + '</option>' for cat in FLUFFY_CHIPS)
        fluffy_dict = {cat["name"]: [[c["label"], c["promptText"]] for c in cat["chips"]] for cat in FLUFFY_CHIPS}
        return build_html(json.dumps(fluffy_dict), json.dumps({k: v for k, v in AI_DEFS.items()}), json.dumps(DEFAULT_CHAINS), cat_options)

    @app.route('/api/prompt', methods=['POST'])
    def api_prompt():
        data = request.get_json()
        category = data.get('category', 'others')
        ai = data.get('ai', get_active_ai())
        prompt = data.get('prompt', '').strip()
        try:
            result = call_ai(ai, category, prompt)
            db_query("INSERT INTO history(ts,category,ai_name,prompt,response) VALUES(?,?,?,?,?)",
                     (datetime.datetime.now().isoformat(), category, ai, prompt, result))
            return jsonify({"ok": True, "response": result})
        except Exception as e:
            return jsonify({"ok": False, "error": str(e)})

    @app.route('/api/rage', methods=['POST'])
    def api_rage():
        data = request.get_json()
        category = data.get('category', 'others')
        ai = data.get('ai', get_active_ai())
        prompt = data.get('prompt', '').strip()
        try:
            result = call_ai(ai, category, prompt, rage=True)
            db_query("INSERT INTO history(ts,category,ai_name,prompt,response) VALUES(?,?,?,?,?)",
                     (datetime.datetime.now().isoformat(), category, ai, prompt, result))
            return jsonify({"ok": True, "response": result})
        except Exception as e:
            return jsonify({"ok": False, "error": str(e)})

    @app.route('/api/settings', methods=['GET'])
    def api_settings_get():
        c = sqlite3.connect(DB_PATH)
        rows = c.execute("SELECT key,value FROM settings").fetchall()
        c.close()
        return jsonify(dict(rows))

    @app.route('/api/settings', methods=['POST'])
    def api_settings_post():
        for k, v in request.get_json().items():
            db_set(k, v)
        return jsonify({"ok": True})

    @app.route('/api/chips', methods=['GET'])
    def api_chips_get():
        cat = request.args.get('category', 'software')
        return jsonify(db_query("SELECT id,category,label,prompt_text FROM custom_chips WHERE category=?", (cat,), fetch=True))

    @app.route('/api/chips', methods=['POST'])
    def api_chips_post():
        d = request.get_json()
        db_query("INSERT INTO custom_chips(category,label,prompt_text) VALUES(?,?,?)",
                 (d.get('category'), d.get('label'), d.get('prompt_text')))
        return jsonify({"ok": True})

    @app.route('/api/chips/<int:cid>', methods=['DELETE'])
    def api_chips_del(cid):
        db_query("DELETE FROM custom_chips WHERE id=?", (cid,))
        return jsonify({"ok": True})

    @app.route('/api/chains', methods=['GET'])
    def api_chains_get():
        return jsonify(db_query("SELECT id,name,steps FROM chains", fetch=True))

    @app.route('/api/chains', methods=['POST'])
    def api_chains_post():
        d = request.get_json()
        db_query("INSERT INTO chains(name,steps) VALUES(?,?)", (d.get('name'), d.get('steps')))
        return jsonify({"ok": True})

    @app.route('/api/chains/<int:cid>', methods=['DELETE'])
    def api_chains_del(cid):
        db_query("DELETE FROM chains WHERE id=?", (cid,))
        return jsonify({"ok": True})

    @app.route('/api/history')
    def api_history():
        return jsonify(db_query("SELECT id,ts,category,ai_name,prompt,response FROM history ORDER BY id DESC LIMIT 50", fetch=True))

    return app

def start_tray():
    try:
        import pystray
        from PIL import Image as PilImage
        icon_img = PilImage.open(ICON_PATH).resize((64, 64))
        def open_ui(icon, item):
            webbrowser.open('http://localhost:' + str(APP_PORT))
        def quit_app(icon, item):
            icon.stop()
            os._exit(0)
        menu = pystray.Menu(pystray.MenuItem("Open Fluffnuts Pro", open_ui, default=True), pystray.MenuItem("Quit", quit_app))
        pystray.Icon("FluffnutsPro", icon_img, "Fluffnuts Pro", menu).run()
    except Exception as e:
        print("Tray: " + str(e))
        threading.Event().wait()

if __name__ == "__main__":
    init_db()
    flask_app = get_app()
    threading.Thread(target=start_tray, daemon=True).start()
    def open_right_popup():
        import subprocess
        width = 900
        height = 1000
        url = 'http://localhost:' + str(APP_PORT)
        try:
            import ctypes
            screen_w = ctypes.windll.user32.GetSystemMetrics(0)
            screen_h = ctypes.windll.user32.GetSystemMetrics(1)
            left = screen_w - width
            top = 0
            height = screen_h - 40
        except Exception:
            left = 800
            top = 0
        chrome_paths = [
            r'C:\Program Files\Google\Chrome\Application\chrome.exe',
            r'C:\Program Files (x86)\Google\Chrome\Application\chrome.exe',
        ]
        for cp in chrome_paths:
            if os.path.exists(cp):
                subprocess.Popen([cp, '--app=' + url, '--window-size=' + str(width) + ',' + str(height), '--window-position=' + str(left) + ',' + str(top)])
                return
        webbrowser.open(url)
    threading.Timer(1.5, open_right_popup).start()
    flask_app.run(host='0.0.0.0', port=APP_PORT, debug=False)
